const msg = $json.body.message?.toString().trim().toLowerCase();
let reply;
switch (msg) {
  case '/start':
    reply = 'Bem-vindo ao WhatsWaiter! Digite "menu" para ver o cardápio.';
    break;
  case 'menu':
    reply = '1. Pizza Margherita\n2. Burger Artesanal\nEnvie o número do item para pedir.';
    break;
  case '1':
    reply = 'Pizza Margherita adicionada ao pedido. Digite "pagar" para finalizar.';
    break;
  case '2':
    reply = 'Burger Artesanal adicionado ao pedido. Digite "pagar" para finalizar.';
    break;
  case 'pagar':
    reply = 'Pagamento via PIX: https://exemplo.com/qrcode-pix';
    break;
  default:
    reply = 'Desculpe, não entendi. Digite "/start" ou "menu".';
}
return { reply };
